    setSelectedFile(null); 
    setYtLinks([]);
    if (fileInputRef.current) fileInputRef.current.value = '';

    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const file = new File([blob], "voice_input.webm", { type: 'audio/webm' });

        // Cleanup stream tracks
        stream.getTracks().forEach(track => track.stop());

        setIsRecording(false);
        setIsTranscribing(true);

        try {
          const text = await transcribeAudio(file);
          if (text && text.trim()) {
            onSendMessage(text.trim(), null, [], isUrlUnderstanding);
          }
        } catch (err) {
          console.error("Transcription error:", err);
          // Use alert or toast here if available, for now console error is fallback
          alert("Failed to transcribe audio.");
        } finally {
          setIsTranscribing(false);
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Microphone access denied or not available.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
    }
  };

  const toggleVoice = () => {
    if (isLoading || isTranscribing) return;
    if (isRecording) stopRecording();
    else startRecording();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.altKey && e.key.toLowerCase() === 's') {
      e.preventDefault();
      handleSubmit();
      return;
    }
    if (e.altKey && e.key.toLowerCase() === 'a') {
      e.preventDefault();
      fileInputRef.current?.click();
      return;
    }
    if (e.altKey && e.key.toLowerCase() === 'd') {
      e.preventDefault();
      toggleVoice();
      return;
    }
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [input]);

  const isSendDisabled = (!input.trim() && !selectedFile && ytLinks.length === 0) || isLoading || isRecording || isTranscribing;

  return (
    <div className="w-full bg-surface border-t border-gray-700/50 px-4 pt-4 pb-6">
      <div role="alert" aria-live="polite" className="sr-only">
        {statusMessage}
        {isRecording && "Recording voice input"}
        {isTranscribing && "Transcribing audio"}
      </div>

      <div className="max-w-3xl mx-auto relative flex flex-col gap-2">
        {/* Attachment Display */}
        <div className="flex flex-wrap gap-2 mb-1">
          {selectedFile && (
             <div className="flex items-center gap-2 bg-background border border-gray-700 rounded-lg px-3 py-2 animate-in slide-in-from-bottom-2">
               <div className="flex flex-col">
                  <p className="text-[10px] text-primary font-bold uppercase tracking-wider">File</p>
                  <p className="text-sm text-gray-200 truncate max-w-[150px]">{selectedFile.name}</p>
               </div>
               <button 
                 onClick={() => { setSelectedFile(null); if (fileInputRef.current) fileInputRef.current.value = ''; }} 
                 className="ml-2 flex items-center gap-1 p-1 hover:bg-gray-700 rounded-lg text-gray-400 hover:text-white transition-colors border border-transparent hover:border-gray-600"
                 title="Remove"
               >
                 <X size={14} />
                 <span className="text-[10px] font-bold uppercase">Remove</span>
               </button>
             </div>
          )}

          {ytLinks.map((link, idx) => (
            <div key={idx} className="flex items-center gap-2 bg-background border border-gray-700 rounded-lg px-3 py-2 animate-in slide-in-from-bottom-2">
               <div className="flex flex-col">
                  <p className="text-[10px] text-red-500 font-bold uppercase tracking-wider">YouTube</p>
                  <p className="text-sm text-gray-200 truncate max-w-[200px]">{link}</p>
               </div>
               <button 
                 onClick={() => setYtLinks(prev => prev.filter((_, i) => i !== idx))} 
                 className="ml-2 flex items-center gap-1 p-1 hover:bg-gray-700 rounded-lg text-gray-400 hover:text-white transition-colors border border-transparent hover:border-gray-600"
                 title="Remove"
               >
                 <X size={14} />
                 <span className="text-[10px] font-bold uppercase">Remove</span>
               </button>
             </div>
          ))}
        </div>

        <form onSubmit={handleSubmit} className="relative flex items-end gap-2 bg-background p-2 rounded-xl border border-gray-700/50 focus-within:border-primary/50 focus-within:ring-1 focus-within:ring-primary/20 transition-all shadow-lg">
          <textarea
            ref={textareaRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={isRecording ? "Listening..." : "Ask AI assistant anything... (Alt+S to send)"}
            disabled={isRecording || isTranscribing}
            className={`w-full bg-transparent text-gray-100 placeholder-gray-500 resize-none outline-none py-3 px-3 min-h-[50px] max-h-[200px] text-sm md:text-base scrollbar-hide ${isRecording ? 'animate-pulse text-red-400' : ''}`}
            rows={1}
          />
          <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*,video/*,audio/*,.pdf,.txt,.md,.js,.ts,.py,.java,.c,.cpp,.html,.css,.json,.csv" />
        </form>

        {/* Toolbar Below Input */}
        <div className="flex items-center justify-between px-1">
          <div className="flex flex-wrap items-center gap-3">
             <button type="button" onClick={() => fileInputRef.current?.click()} disabled={isRecording} className="flex items-center gap-2 text-xs font-medium text-gray-400 hover:text-white transition-colors py-1 px-2 rounded hover:bg-gray-800 disabled:opacity-50" title="Add Files (Alt+A)">
               <Paperclip size={14} />
               <span>Add Files</span>
             </button>

             <button type="button" onClick={() => setIsYtModalOpen(true)} disabled={isRecording} className="flex items-center gap-2 text-xs font-medium text-gray-400 hover:text-white transition-colors py-1 px-2 rounded hover:bg-gray-800 disabled:opacity-50" title="Add YouTube links">
               <Youtube size={14} className="text-red-500" />
               <span>Add YouTube links</span>
             </button>

             <button
               type="button"
               onClick={() => setIsUrlUnderstanding(!isUrlUnderstanding)}
               disabled={isRecording}
               className={`flex items-center gap-2 text-xs font-medium transition-all py-1 px-2 rounded border disabled:opacity-50 ${isUrlUnderstanding ? 'bg-primary/20 border-primary/50 text-primary' : 'bg-transparent border-transparent text-gray-400 hover:bg-gray-800 hover:text-white'}`}
               title={isUrlUnderstanding ? "Disable URL understanding" : "Enable URL understanding"}
             >
               <Globe size={14} />
               <span>URL Understanding</span>
               <div className={`w-6 h-3 rounded-full relative transition-colors ${isUrlUnderstanding ? 'bg-primary' : 'bg-gray-600'}`}>
                 <div className={`absolute top-0.5 w-2 h-2 rounded-full bg-white transition-transform ${isUrlUnderstanding ? 'left-3.5' : 'left-0.5'}`} />
               </div>
             </button>

             <button
               type="button"
               onClick={toggleVoice}
               disabled={isLoading || isTranscribing}
               className={`flex items-center gap-2 text-xs font-bold transition-all py-1 px-3 rounded-full border ${isRecording ? 'bg-red-500/20 border-red-500 text-red-500 animate-pulse' : 'bg-gray-800 border-gray-700 text-gray-300 hover:bg-gray-700 hover:text-white'}`}
               title="Toggle Voice Input (Alt+D)"
             >
               {isTranscribing ? (
                 <>
                  <Loader2 size={14} className="animate-spin" />
                  <span>Processing...</span>
                 </>
               ) : isRecording ? (
                 <>
                   <Square size={14} fill="currentColor" />
                   <span>Stop Voice Input</span>
                 </>
               ) : (
                 <>
                   <Mic size={14} />
                   <span>Start Voice Input</span>
                 </>
               )}
             </button>
          </div>

          <button
            onClick={() => handleSubmit()}
            disabled={isSendDisabled}
            title="ALT+S"
            className={`px-4 py-2.5 rounded-lg flex-shrink-0 transition-all duration-200 flex items-center gap-2 ${isSendDisabled ? 'bg-gray-800 text-gray-500 cursor-not-allowed' : 'bg-primary text-white hover:bg-blue-600 shadow-lg shadow-blue-500/20 active:scale-95'}`}
          >
            {isLoading ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
            <span className="text-sm font-bold whitespace-nowrap">Send prompt</span>
          </button>
        </div>
      </div>

      <YouTubeModal 
        isOpen={isYtModalOpen} 
        onClose={() => setIsYtModalOpen(false)} 
        onAdd={(url) => setYtLinks(prev => [...prev, url])} 
      />
    </div>
  );
});

ChatInput.displayName = 'ChatInput';
